    23→const ToolBar = ({addUploadedImagePath}) =>{
    24→    const [editor] = useLexicalComposerContext();
    25→    const {session} = useAuth();
    26→    const colorPickerRef = useRef(null);
    27→
    28→    // Active state tracking
    29→    const [activeStates, setActiveStates] = useState({
    30→        bold: false,
    31→        italic: false,
    32→        underline: false,
    33→        heading: null,   // 'h1' | 'h2' | 'h3' | null
    34→        quote: false,
    35→        alignment: 'left',
    36→        textColor: '',
    37→        highlightColor: '',
    38→    });
    39→
    40→    const [showTextColorPicker, setShowTextColorPicker] = useState(false);
