    52→        { label: 'Deep Purple', value: '#673ab7' },
    53→        { label: 'Indigo', value: '#3f51b5' },
    54→        { label: 'Blue', value: '#2196f3' },
    55→        { label: 'Light Blue', value: '#03a9f4' },
