    29→    this.__loading = loading;
    30→    this.__rotation = rotation;
    31→  }
    32→
    33→  createDOM() {
    34→    const div = document.createElement("div");
    35→    div.className = 'image-container'
    36→    return div;
    37→  }
    38→
    39→  updateDOM() {
    40→    return false;
    41→  }
    42→
    43→  exportJSON() {
    44→    return {
    45→      type: "image",
    46→      version: 1,
    47→      src: this.__src,
    48→      width: this.__width,
    49→      height: this.__height,
    50→      rotation: this.__rotation,
    51→    };
    52→  }
    53→
    54→  static importJSON(serializedNode) {
    55→    const { src, width, height, rotation } = serializedNode;
    56→    return $createImageNode(src, width, height, false, rotation);
    57→  }
    58→
    59→  // update dimensions when user resizes
    60→  setWidthAndHeight(width, height) {
    61→    const writable = this.getWritable();
    62→    writable.__width = width;
    63→    writable.__height = height;
    64→  }
    65→
    66→  setRotation(rotation) {
    67→    const writable = this.getWritable();
    68→    writable.__rotation = rotation;
    69→  }
    70→
    71→  setSrcAndLoading(src, loading) {
    72→    const writable = this.getWritable();
    73→    writable.__src = src;
    74→    writable.__loading = loading;
    75→  }
    76→
    77→  getWidth() {
    78→    return this.__width;
    79→  }
    80→
    81→  getHeight() {
    82→    return this.__height;
    83→  }
    84→
    85→  decorate(editor) {
    86→    const src = this.__src;
    87→    const nodeKey = this.getKey();
    88→    const width = this.__width;
    89→    const height = this.__height;
    90→    const loading = this.__loading;
    91→    const rotation = this.__rotation;
    92→    const isEditable = editor.isEditable();
    93→    return <ResizableImageComponent src={src} nodeKey={nodeKey} width={width} height={height} loading={loading} rotation={rotation} isEditable={isEditable}/>;
    94→  }
    95→}
    96→
    97→//helper function to create ImageNode
    98→export function $createImageNode(src, width = 400, height = 300, loading = false, rotation = 0) {
    99→  return new ImageNode(src, width, height, loading, rotation);
